/**
 * @param {string} lStr - The lower bound as a string (since l and r can be large).
 * @param {string} rStr - The upper bound as a string.
 * @param {string} directions - The direction string.
 * @returns {number} The count of "good" integers in [l, r].
 */
function solve(lStr, rStr, directions) {
    const L = BigInt(lStr);
    const R = BigInt(rStr);

    /**
     * Checks if a given number x is a "good" integer.
     * @param {BigInt} x - The number to check.
     * @param {string} directions - The direction string.
     * @returns {boolean} True if x is a good integer, false otherwise.
     */
    const isGood = (x, directions) => {
        // 1. Format x to a 16-digit string with leading zeros.
        let xStr = x.toString();
        while (xStr.length < 16) {
            xStr = "0" + xStr;
        }

        // 2. Create the 4x4 grid.
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        for (let i = 0; i < 16; i++) {
            const digit = parseInt(xStr[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
        }

        // 3. Traverse the path and record the sequence.
        let row = 0;
        let col = 0;
        const sequence = [];

        // Start at (0, 0) and record the first element
        sequence.push(grid[row][col]);

        // Directions string has length 6, so 6 moves are applied.
        for (let i = 0; i < 6; i++) {
            const move = directions[i];

            if (move === 'D') {
                row += 1;
            } else if (move === 'R') {
                col += 1;
            }

            // The problem description implies the path is always valid within 4x4 grid,
            // as the sequence length is 7 (1 initial + 6 moves).
            // If the rules allowed out-of-bounds, we'd need bounds checks, 
            // but based on the problem statement structure, we assume the moves lead to valid indices for 7 steps.

            // Record the digit at the new position
            if (row >= 0 && row < 4 && col >= 0 && col < 4) {
                sequence.push(grid[row][col]);
            } else {
                // Should not happen based on problem constraints/examples, but defensive coding.
                return false; 
            }
        }

        // 4. Check if the sequence is non-decreasing.
        for (let i = 0; i < sequence.length - 1; i++) {
            if (sequence[i] > sequence[i+1]) {
                return false;
            }
        }

        return true;
    };

    let count = 0;
    let current = L;
    const R_big = R;

    while (current <= R_big) {
        if (isGood(current, directions)) {
            count++;
        }
        current = current + 1n;
    }

    return count;
}

