class Solution {
    /**
     * Checks if a given number x is a "good" integer.
     * @param long x - The number to check.
     * @param String directions - The direction string.
     * @return boolean True if x is a good integer, false otherwise.
     */
    private boolean isGood(long x, String directions) {
        // 1. Format x to a 16-digit string with leading zeros.
        String xStr = String.format("%16d", x);

        // 2. Create the 4x4 grid.
        int[][] grid = new int[4][4];
        for (int i = 0; i < 16; i++) {
            int digit = xStr.charAt(i) - '0';
            int row = i / 4;
            int col = i % 4;
            grid[row][col] = digit;
        }

        // 3. Traverse the path and record the sequence.
        int row = 0;
        int col = 0;
        java.util.List<Integer> sequence = new java.util.ArrayList<>();

        // Start at (0, 0) and record the first element
        sequence.add(grid[row][col]);

        // Directions string has length 6, so 6 moves are applied.
        for (int i = 0; i < 6; i++) {
            char move = directions.charAt(i);

            if (move == 'D') {
                row += 1;
            } else if (move == 'R') {
                col += 1;
            }

            // Record the digit at the new position
            // Since we know directions has 3 'D' and 3 'R', the max row change is 3 (0->3) and max col change is 3 (0->3).
            // The path length is 7 (1 initial + 6 moves). 
            // The starting position (0,0) and 6 subsequent moves ensure all positions are within the 4x4 grid bounds [0, 3].
            sequence.add(grid[row][col]);
        }

        // 4. Check if the sequence is non-decreasing.
        for (int i = 0; i < sequence.size() - 1; i++) {
            if (sequence.get(i) > sequence.get(i + 1)) {
                return false;
            }
        }

        return true;
    }

    public static long solve(long l, long r, String directions) {
        Solution solution = new Solution();
        long count = 0;
        for (long x = l; x <= r; x++) {
            if (solution.isGood(x, directions)) {
                count++;
            }
        }
        return count;
    }
}
